export const getAbilityImage = (champId, key) => {
  const champ = ABILITY_MAP[champId]
  if (!champ) return null
  const spellKey = champ[key]
  if (!spellKey) return null
  if (spellKey.startsWith('http')) return spellKey
  if (key === 'P') return `${PASSIVE}/${spellKey}.png`
  return `${DD}/${spellKey}.png`
}
